            self.drawnRefs["HEAD"].next_to(ref, m.UP)
            self.drawnRefs[self.repo.active_branch.name].next_to(
                self.drawnRefs["HEAD"], m.UP
            )

    def translate_frame(self, shift):
        if settings.animate:
            self.play(self.camera.frame.animate.shift(shift))
        else:
            self.camera.frame.shift(shift)

    def setup_and_draw_parent(
        self,
        child,
        commitMessage="New commit",
        shift=numpy.array([0.0, 0.0, 0.0]),
        draw_arrow=True,
        color=m.RED,
    ):
        circle = m.Circle(
            stroke_color=color,
            stroke_width=self.commit_stroke_width,
            fill_color=color,
            fill_opacity=self.ref_fill_opacity,
        )
        circle.height = 1
        if child != "dark":
            circle.next_to(
                self.drawnCommits[child.hexsha],
                m.LEFT if settings.reverse else m.RIGHT,
                buff=1.5,
            )

        circle.shift(shift)

        if child != "dark":
            start = circle.get_center()
            end = self.drawnCommits[child.hexsha].get_center()
            arrow = m.Arrow(
                start,
                end,
                color=self.fontColor,
                stroke_width=self.arrow_stroke_width,
                tip_shape=self.arrow_tip_shape,
                max_stroke_width_to_length_ratio=1000,
            )
            length = numpy.linalg.norm(start - end) - (1.5 if start[1] == end[1] else 3)
            arrow.set_length(length)

        commitId = m.Text(
            "abcdef",
            font=self.font,
            font_size=20,
            color=self.fontColor,
            weight=self.font_weight,
        ).next_to(circle, m.UP)
        self.toFadeOut.add(commitId)

        commitMessage = commitMessage.split("\n")[0][:40].replace("\n", " ")
        message = m.Text(
            "\n".join(
                commitMessage[j : j + 20] for j in range(0, len(commitMessage), 20)
            )[:100],
            font=self.font,
            font_size=14,
            color=self.fontColor,
            weight=self.font_weight,
        ).next_to(circle, m.DOWN)
        self.toFadeOut.add(message)

        if settings.animate:
            self.play(
                self.camera.frame.animate.move_to(circle.get_center()),
                m.Create(circle),
                m.AddTextLetterByLetter(commitId),
                m.AddTextLetterByLetter(message),
                run_time=1 / settings.speed,
            )
        else:
            self.camera.frame.move_to(circle.get_center())
            self.add(circle, commitId, message)

        self.drawnCommits["abcdef"] = circle
        self.toFadeOut.add(circle)

        if draw_arrow and child != "dark":
            if settings.animate:
                self.play(m.Create(arrow), run_time=1 / settings.speed)
            else:
                self.add(arrow)
            self.arrows.append(arrow)
            self.toFadeOut.add(arrow)

        return commitId

    def draw_arrow_between_commits(self, startsha, endsha):
        start = self.drawnCommits[startsha].get_center()
        end = self.drawnCommits[endsha].get_center()

        arrow = DottedLine(
            start, end, color=self.fontColor, dot_kwargs={"color": self.fontColor}
        ).add_tip()
        length = numpy.linalg.norm(start - end) - 1.65
        arrow.set_length(length)
        self.draw_arrow(True, arrow)

    def create_dark_commit(self):
        return "dark"

    def get_nondark_commits(self):
        nondark_commits = []
        return nondark_commits

    def draw_ref(self, commit, top, i=0, text="HEAD", color=m.BLUE):
        refText = m.Text(
            text,
            font=self.font,
            font_size=20,
            color=self.fontColor,
            weight=self.font_weight,
        )
        refbox = m.Rectangle(
            color=color,
            fill_color=color,
            fill_opacity=self.ref_fill_opacity,
            height=0.4,
            width=refText.width + 0.25,
        )
        refbox.next_to(top, m.UP)
        refText.move_to(refbox.get_center())

        ref = m.VGroup(refbox, refText)

        if settings.animate:
            self.play(m.Create(ref), run_time=1 / settings.speed)
        else:
            self.add(ref)

        self.toFadeOut.add(ref)
        self.drawnRefs[text] = ref
        self.prevRef = ref

        if i == 0 and self.first_parse:
            self.topref = self.prevRef

    def draw_dark_ref(self):
        refRec = m.Rectangle(
            color=m.WHITE if settings.light_mode else m.BLACK,
            fill_color=m.WHITE if settings.light_mode else m.BLACK,
            height=0.4,
            width=1,
        )
        refRec.next_to(self.prevRef, m.UP)
        self.add(refRec)
        self.toFadeOut.add(refRec)
        self.prevRef = refRec

    def trim_path(self, path):
        return f"{path[:15]}...{path[-15:]}" if len(path) > 33 else path

    def trim_cmd(self, path, length=30):
        return f"{path[:length]}..." if len(path) > (length + 3) else path

    def get_remote_tracking_branches(self):
        remote_refs = [remote.refs for remote in self.repo.remotes]
        remote_tracking_branches = {}
        for reflist in remote_refs:
            for ref in reflist:
                if "HEAD" not in ref.name and ref.name not in remote_tracking_branches:
                    remote_tracking_branches[ref.name] = ref.commit.hexsha
        return remote_tracking_branches

    def create_zone_text(
        self,
        firstColumnFileNames,
        secondColumnFileNames,
        thirdColumnFileNames,
        firstColumnFiles,
        secondColumnFiles,
        thirdColumnFiles,
        firstColumnFilesDict,
        secondColumnFilesDict,
        thirdColumnFilesDict,
        firstColumnTitle,
        secondColumnTitle,
        thirdColumnTitle,
        horizontal2,
    ):
        for i, f in enumerate(firstColumnFileNames):
            text = (
                m.Text(
                    self.trim_path(f),
                    font=self.font,
                    font_size=24,
                    color=self.fontColor,
                )
                .move_to(
                    (firstColumnTitle.get_center()[0], horizontal2.get_center()[1], 0)
                )
                .shift(m.DOWN * 0.5 * (i + 1))
            )
            firstColumnFiles.add(text)
            firstColumnFilesDict[f] = text

        for j, f in enumerate(secondColumnFileNames):
            text = (
                m.Text(
                    self.trim_path(f),
                    font=self.font,
                    font_size=24,
                    color=self.fontColor,
                )
                .move_to(
                    (secondColumnTitle.get_center()[0], horizontal2.get_center()[1], 0)
                )
                .shift(m.DOWN * 0.5 * (j + 1))
            )
            secondColumnFiles.add(text)
            secondColumnFilesDict[f] = text

        for h, f in enumerate(thirdColumnFileNames):
            text = (
                m.Text(
                    self.trim_path(f),
                    font=self.font,
                    font_size=24,
                    color=self.fontColor,
                )
                .move_to(
                    (thirdColumnTitle.get_center()[0], horizontal2.get_center()[1], 0)
                )
                .shift(m.DOWN * 0.5 * (h + 1))
            )
            thirdColumnFiles.add(text)
            thirdColumnFilesDict[f] = text

    def color_by(self, offset=0):
        if settings.color_by == ColorByOptions.AUTHOR:
            sorted_authors = sorted(
                self.author_groups.keys(),
                key=lambda k: len(self.author_groups[k]),
                reverse=True,
            )
            for i, author in enumerate(sorted_authors):
                authorText = m.Text(
                    f"{author[:15]} ({str(len(self.author_groups[author]))})",
                    font=self.font,
                    font_size=36,
                    color=self.colors[int(i % 11)],
                    weight=self.font_weight,
                )
                authorText.move_to(
                    [(-5 - offset) if settings.reverse else (5 + offset), -i, 0]
                )
                self.toFadeOut.add(authorText)
                if i == 0:
                    self.recenter_frame()
                    self.scale_frame()
                if settings.animate:
                    self.play(m.AddTextLetterByLetter(authorText))
                else:
                    self.add(authorText)
                for g in self.author_groups[author]:
                    g[0].set_color(self.colors[int(i % 11)])
            self.recenter_frame()
            self.scale_frame()

        elif settings.color_by == ColorByOptions.BRANCH:
            pass

        elif settings.color_by == ColorByOptions.NOTLOCAL1:
            for commit_id in self.drawnCommits:
                try:
                    self.orig_repo.commit(commit_id)
                except ValueError:
                    self.drawnCommits[commit_id].set_color(m.GOLD)

        elif settings.color_by == ColorByOptions.NOTLOCAL2:
            for commit_id in self.drawnCommits:
                if not self.orig_repo.is_ancestor(commit_id, "HEAD"):
                    self.drawnCommits[commit_id].set_color(m.GOLD)

    def add_group_to_author_groups(self, author, group):
        if author not in self.author_groups:
            self.author_groups[author] = [group]
        else:
            self.author_groups[author].append(group)

    def show_command_as_title(self):
        if settings.show_command_as_title:
            titleText = m.Text(
                self.trim_cmd(self.cmd),
                font=self.font,
                font_size=36,
                color=self.fontColor,
            )
            top = 0
            for element in self.toFadeOut:
                if element.get_top()[1] > top:
                    top = element.get_top()[1]
            titleText.move_to(
                (
                    self.camera.frame.get_x(),
                    top + titleText.height * 2,
                    0,
                )
            )
            ul = m.Underline(
                titleText,
                color=self.fontColor,
            )
            self.toFadeOut.add(titleText, ul)
            self.scale_frame()
            if settings.animate:
                self.play(m.AddTextLetterByLetter(titleText), m.Create(ul))
            else:
                self.add(titleText, ul)

    def del_rw(self, action, name, exc):
        os.chmod(name, stat.S_IWRITE)
        os.remove(name)

    def head_exists(self):
        try:
            hc = self.repo.head.commit
        except ValueError:
            return False
        return True

    def check_all_dark(self):
        if not self.drawnCommits:
            return True
        return False

    def add_ref_to_drawn_refs_by_commit(self, hexsha, ref):
        try:
            self.drawnRefsByCommit[hexsha].append(ref)
        except KeyError:
            self.drawnRefsByCommit[hexsha] = [
                ref,
            ]

import sys
import git
import manim as m
from typing import List
from git_sim.git_sim_base_command import GitSimBaseCommand
from git_sim.settings import settings

class Add(GitSimBaseCommand):
    def __init__(self, files: List[str]):
        super().__init__()
        self.hide_first_tag = True
        self.allow_no_commits = True
        self.files = files
        settings.hide_merged_branches = True
        self.n = self.n_default

        try:
            self.selected_branches.append(self.repo.active_branch.name)
        except TypeError:
            pass

        for file in self.files:
            if file not in [x.a_path for x in self.repo.index.diff(None)] + [
                z for z in self.repo.untracked_files
            ]:
                print(f"git-sim error: No modified file with name: '{file}'")
                sys.exit()

        self.cmd += f"{type(self).__name__.lower()} {' '.join(self.files)}"

    def construct(self):
        if not settings.stdout and not settings.output_only_path and not settings.quiet:
            print(f"{settings.INFO_STRING} {self.cmd}")

        self.show_intro()
        self.parse_commits()
        self.recenter_frame()
        self.scale_frame()
        self.vsplit_frame()
        self.setup_and_draw_zones()
        self.show_command_as_title()
        self.fadeout()
        self.show_outro()

    def populate_zones(
        self,
        firstColumnFileNames,
        secondColumnFileNames,
        thirdColumnFileNames,
        firstColumnArrowMap={},
        secondColumnArrowMap={},
        thirdColumnArrowMap={},
    ):
        for x in self.repo.index.diff(None):
            if "git-sim_media" not in x.a_path:
                secondColumnFileNames.add(x.a_path)
                for file in self.files:
                    if file == x.a_path:
                        thirdColumnFileNames.add(x.a_path)
                        secondColumnArrowMap[x.a_path] = m.Arrow(
                            stroke_width=3, color=self.fontColor
                        )
        try:
            for y in self.repo.index.diff("HEAD"):
                if "git-sim_media" not in y.a_path:
                    thirdColumnFileNames.add(y.a_path)
        except git.exc.BadName:
            for (y, _stage), entry in self.repo.index.entries.items():
                if "git-sim_media" not in y:
                    thirdColumnFileNames.add(y)

        for z in self.repo.untracked_files:
            if "git-sim_media" not in z:
                firstColumnFileNames.add(z)
                for file in self.files:
                    if file == z:
                        thirdColumnFileNames.add(z)
                        firstColumnArrowMap[z] = m.Arrow(
                            stroke_width=3, color=self.fontColor
                        )

from manimlib.imports import *

class SinCos(Scene):
    CONFIG = {
        "total_time": 25, # seconds
        "dt_factor": 0.4,
        "circle_config": {
            "radius": 1.5,
            "color": WHITE,
            "arc_center": [5,-2,0]
        },
        "cos_config": {
            "color": BLUE
        },
        "sin_config": {
            "color": RED
        },
        "vertical_line_config": {
            "stroke_width": 2,
            "stroke_opacity": 0.5,
            "color": TEAL
        },
        "arc_marks_config": {
            "color": GRAY,
            "stroke_width": 2,
            "stroke_opacity": 0.5
        },
        "sto": 0, # sine t offset
        "cto": 0,
        "tto": 0, # theta t offset
    }
    def construct(self):
        # Create Main Mobjects
        sine   = self.sine   = SinFunc()
        cosine = self.cosine = CosFunc()
        circle = self.circle = Circle(**self.circle_config)
        circle.next_to(sine, RIGHT, buff=0.5)
        dot_theta = self.dot_theta = self.get_dot_from_theta(circle,0)
        # guide lines
        sine_line   = self.sine_line   = self.get_sine_line()
        cosine_guide_line = self.cgl   = self.get_cosine_vertical_guide_line()
        cosine_line = self.cosine_line = self.get_cosine_line()
        # reference lines
        vertical_line   = self.vertical_line   = self.get_vertical_line()
        horizontal_line = self.horizontal_line = self.get_horizontal_line()
        # arc marks
        arc_dx = 0.5
        arc_marks = VGroup(*[
            Arc(
                radius=r,
                arc_center=[vertical_line.get_x(),0,0],
                **self.arc_marks_config
            )
            for r in np.arange(0.5, 3.5 + arc_dx, arc_dx)
        ])
        # Decimal number mobjects
        theta_tex = TexMobject("\\theta =")
        theta_tex.to_corner(UR).shift(LEFT * 1.5)
        theta_number = DecimalNumber(0,unit=r"^\circ")
        theta_number.next_to(theta_tex, RIGHT)
        theta_number.align_to(theta_tex, DOWN)
        # Write in the Screen
        self.play(
            ShowCreation(VGroup(
                vertical_line, horizontal_line
            )),
            GrowFromCenter(circle),
            GrowFromPoint(dot_theta, circle.get_center()),
            run_time=2.5
        )
        self.play(
            *list(map(ShowCreation,[
                sine,
                cosine,
                arc_marks,
                sine_line,
                VGroup(cosine_guide_line, cosine_line) # WHY this?, think about it
            ])),
            Write(VGroup(theta_tex, theta_number)),
            run_time=2.5
        )
        self.wait()
        #Â Add updaters, THE ORDER MATTERS
        sine.add_updater(
            self.get_updater_func("sto", SinFunc)
        )
        cosine.add_updater(
            self.get_updater_func("cto", CosFunc)
        )
        dot_theta.add_updater(
            self.get_updater_dot(circle)
        )
        sine_line.add_updater(
            lambda mob: mob.become(
                self.get_sine_line()
            )
        )
        cosine_guide_line.add_updater(
            lambda mob: mob.become(
                self.get_cosine_vertical_guide_line()
            )
        )
        cosine_line.add_updater(
            lambda mob: mob.become(
                self.get_cosine_line()
            )
        )
        theta_number.add_updater(
            lambda mob: mob.set_value(
                (self.CONFIG["tto"] % (2*PI)) * 180 / PI
            )
        )
        self.wait(self.total_time)
        # Stop animation
        for mob in [
            sine,
            cosine,
            dot_theta,
            sine_line,
            cosine_guide_line,
            cosine_line,
            theta_number,
        ]:
            mob.clear_updaters()
        self.wait(2)

    def get_updater_func(self, t, TrigFunc, **kwargs):
        def update_func(mob,dt):
            self.CONFIG[t] += dt * self.dt_factor
            mob.become(
                TrigFunc(
                    t_offset=self.CONFIG[t],
                    **kwargs
                )
            )
        return update_func

    def get_dot_from_theta(self,circle,theta,**kwargs):
        return Dot(
            circle.point_at_angle(theta),
            **kwargs
        )

    def get_updater_dot(self, circle):
        def update_func(mob,dt):
            self.CONFIG["tto"] += dt * self.dt_factor
            mob.move_to(
                circle.point_at_angle(self.CONFIG["tto"]%(2*PI))
            )
        return update_func

    def get_sine_line(self):
        return Line(
            self.sine.get_end(),
            self.dot_theta.get_left(),
            color=self.sine.get_color()
        )

    def get_cosine_line(self):
        return ArcBetweenPoints(
            self.cgl.get_end(),
            self.cosine.get_end(),
            angle=PI/2,
            color=self.cosine.get_color()
        )

    def get_vertical_line(self):
        vertical_line = Line(
                                ORIGIN,
                                RIGHT * FRAME_HEIGHT,
                                **self.vertical_line_config
        ).rotate(PI/2)
        vertical_line.set_x(self.cosine.get_end()[0])
        return vertical_line

    def get_horizontal_line(self):
        return Line(
            LEFT  * FRAME_X_RADIUS,
            RIGHT * FRAME_X_RADIUS,
            **self.vertical_line_config
        )

    def get_cosine_vertical_guide_line(self):
        return Line(
            self.dot_theta.get_top(),
            np.array([
                self.dot_theta.get_x(),
                0,
                0
            ]),
            color=self.cosine.get_color()
        )

from manimlib.imports import *

class SumExternalAngles(ExampleScene):
    CONFIG = {
        "polygon_sides": [3,5,6,7,4],
        "init_buff": 0.6
    }
    def construct(self):
        figures = VGroup(*[GroupRegularPolygon(n) for n in self.polygon_sides])
        for figure in figures:
            figure.save_state()
            figure.height = figure.get_figure_height()

        def shrink_polygon(vgroup,alpha):
            buff = interpolate(self.init_buff,2,alpha)
            for mob in vgroup:
                mob.restore()
                d_height = interpolate(mob.height,0.0001,alpha)
                mob.become(
                    GroupRegularPolygon(
                            mob.get_number_sides(),
                            height = d_height
                        )
                )
            vgroup.arrange(RIGHT,buff=buff)
            vgroup.set_width(FRAME_WIDTH-0.2)

        shrink_polygon(figures,0)
        self.play(LaggedStartMap(GrowFromCenter,figures))
        self.wait()
        self.play(
            UpdateFromAlphaFunc(figures,shrink_polygon),
            run_time = 6,
            rate_func = there_and_back_with_pause
        )
        self.wait()

