        self.right_group = PythagoreanGroupTwoSquares()
        self.left_group.generate_target()
        VGroup(
            self.left_group.target, self.right_group
        ).arrange(RIGHT,buff=1)
        self.play(
            MoveToTarget(self.left_group)
        )
