        # self.play(
        #     TransformFromCopy(
        #         self.left_group.triangles,
        #         self.right_group.triangles
        #     ),
        #     run_time=4
        # )
        self.play(
            LaggedStart(*[
                MoveAndShift(
                    s_t.copy(), e_t.get_center(), angle,
                    run_time=1.7
                )
                for s_t, e_t, angle in zip(
                    self.left_group.triangles, self.right_group.triangles,
                    [0, 0, -PI/2, PI/2]
                )
            ])
        )
        self.wait()

    @print_name
    def show_sub_squares_and_subformulas(self):
