            stroke_opacity=2,
            fill_opacity=DEFAULT_OPACITY
        )
        # formulas definition
        formulas = VGroup(*[
            TexMobject(t)[0].move_to(square)
            for t,square in zip(["c^2","a^2","b^2"], group)
